insert into systems (id, name, description, order_index, published) values ('arranque-carga', 'Arranque y Carga', 'Batería, motor de arranque, alternador, relés y fusibles del sistema eléctrico del vehículo.', 1, true) on conflict (id) do update set name = excluded.name, description = excluded.description, order_index = excluded.order_index, published = excluded.published;
insert into components (id, system_id, name, short_role, full_description, how_to_test, failure_signs, scene_key, order_index) values ('battery', 'arranque-carga', 'Batería', 'Almacena y entrega la energía eléctrica del vehículo.', 'El almacén de energía del vehículo. Entrega la corriente para arrancar el motor y estabiliza el sistema eléctrico. Se recarga con el alternador cuando el motor está en marcha. Sin batería sana, nada funciona.', '{"tool":"Multímetro (V DC)","steps":["Sonda roja al borne positivo, negra al negativo.","En reposo debe marcar 12.4–12.7V (cargada).","Durante el arranque no debe bajar de 9.6V.","Con el motor encendido debe marcar 13.8–14.4V (confirma que recibe carga)."],"normal_values":"Reposo: 12.4–12.7V · Arranque: ≥9.6V · Motor encendido: 13.8–14.4V"}'::jsonb, '{"symptoms":["El arranque suena lento o solo hace \"clic\".","Luces débiles.","Bornes sulfatados (polvo blanco/verde) causan falsos contactos."],"common_causes":["Celda dañada.","Fuga de corriente.","Bornes sulfatados o flojos."]}'::jsonb, 'battery', 1 on conflict (id) do update set system_id = excluded.system_id, name = excluded.name, short_role = excluded.short_role, full_description = excluded.full_description, how_to_test = excluded.how_to_test, failure_signs = excluded.failure_signs, scene_key = excluded.scene_key, order_index = excluded.order_index;
insert into components (id, system_id, name, short_role, full_description, how_to_test, failure_signs, scene_key, order_index) values ('terminal-pos', 'arranque-carga', 'Borne positivo', 'Une eléctricamente el borne positivo de la batería al vehículo.', 'Une eléctricamente el borne positivo de la batería con el cable del vehículo. Un mal contacto aquí se comporta igual que una batería en mal estado.', '{"tool":"Multímetro (V DC) + inspección visual","steps":["Inspección visual: buscar sulfatación (polvo blanco/verde) o borne flojo.","Con el motor cranqueando, mide la caída de voltaje entre el borne y el cable.","Caída sana: menor a 0.1V."],"normal_values":"Caída de voltaje <0.1V durante el arranque"}'::jsonb, '{"symptoms":["Arranque intermitente: a veces prende, a veces solo hace clic.","Apagones intermitentes del sistema eléctrico."],"common_causes":["Sulfatación del borne.","Borne flojo o mal ajustado."]}'::jsonb, 'terminal-pos', 2 on conflict (id) do update set system_id = excluded.system_id, name = excluded.name, short_role = excluded.short_role, full_description = excluded.full_description, how_to_test = excluded.how_to_test, failure_signs = excluded.failure_signs, scene_key = excluded.scene_key, order_index = excluded.order_index;
insert into components (id, system_id, name, short_role, full_description, how_to_test, failure_signs, scene_key, order_index) values ('terminal-neg', 'arranque-carga', 'Borne negativo', 'Une eléctricamente el borne negativo de la batería a la masa del vehículo.', 'Une eléctricamente el borne negativo de la batería con el cable de masa del vehículo. Igual de importante que el borne positivo: sin buen contacto aquí, el circuito no cierra bien.', '{"tool":"Multímetro (V DC) + inspección visual","steps":["Inspección visual: buscar sulfatación o borne flojo.","Con el motor cranqueando, mide la caída de voltaje entre el borne y el cable de masa.","Caída sana: menor a 0.1V."],"normal_values":"Caída de voltaje <0.1V durante el arranque"}'::jsonb, '{"symptoms":["Arranque intermitente: a veces prende, a veces solo hace clic.","Apagones intermitentes del sistema eléctrico."],"common_causes":["Sulfatación del borne.","Borne flojo o mal ajustado."]}'::jsonb, 'terminal-neg', 3 on conflict (id) do update set system_id = excluded.system_id, name = excluded.name, short_role = excluded.short_role, full_description = excluded.full_description, how_to_test = excluded.how_to_test, failure_signs = excluded.failure_signs, scene_key = excluded.scene_key, order_index = excluded.order_index;
insert into components (id, system_id, name, short_role, full_description, how_to_test, failure_signs, scene_key, order_index) values ('ground-strap', 'arranque-carga', 'Trenza de masa', 'Cierra el circuito retornando la corriente al negativo por el chasis.', 'Cierra el circuito eléctrico: retorna la corriente de la batería al negativo a través del chasis o el bloque del motor.', '{"tool":"Multímetro (V DC y Ω)","steps":["Con el motor cranqueando, mide la caída de voltaje entre la masa y la batería.","Caída sana: menor a 0.2V.","Circuito desenergizado: la resistencia debe ser aproximadamente 0Ω."],"normal_values":"Caída de voltaje <0.2V en crank · Resistencia ~0Ω"}'::jsonb, '{"symptoms":["Luces raras (fallas \"fantasma\").","Arranque débil sin causa aparente."],"common_causes":["Corrosión en la trenza o su punto de anclaje."]}'::jsonb, 'ground-strap', 4 on conflict (id) do update set system_id = excluded.system_id, name = excluded.name, short_role = excluded.short_role, full_description = excluded.full_description, how_to_test = excluded.how_to_test, failure_signs = excluded.failure_signs, scene_key = excluded.scene_key, order_index = excluded.order_index;
insert into components (id, system_id, name, short_role, full_description, how_to_test, failure_signs, scene_key, order_index) values ('main-fuse', 'arranque-carga', 'Fusible principal', 'Protege el circuito principal de sobrecorriente.', 'Protege el circuito principal de sobrecorriente. Si detecta un cortocircuito aguas abajo, se quema para evitar daños mayores al cableado.', '{"tool":"Multímetro (Ω) — circuito desenergizado","steps":["Con la llave en OFF, mide continuidad entre sus dos terminales.","Fusible sano: continuidad, aproximadamente 0Ω.","Fusible quemado: sin continuidad, el multímetro marca OL.","Verifica también que haya voltaje presente a ambos lados con el circuito energizado."],"normal_values":"~0Ω sano · OL si está quemado"}'::jsonb, '{"symptoms":["Sistema muerto total: sin luces, sin nada."],"common_causes":["Cortocircuito aguas abajo que lo quema."]}'::jsonb, 'main-fuse', 5 on conflict (id) do update set system_id = excluded.system_id, name = excluded.name, short_role = excluded.short_role, full_description = excluded.full_description, how_to_test = excluded.how_to_test, failure_signs = excluded.failure_signs, scene_key = excluded.scene_key, order_index = excluded.order_index;
insert into components (id, system_id, name, short_role, full_description, how_to_test, failure_signs, scene_key, order_index) values ('ignition-switch', 'arranque-carga', 'Llave de encendido', 'El interruptor que manejas con la llave; reparte la corriente según su posición.', 'Es el interruptor que accionas con la llave. Tiene tres posiciones: OFF (todo apagado), ON (da corriente al tablero y a los sistemas, lo que llamamos ''contacto''), y START (además manda la orden de arranque). En START vuelve sola a ON apenas la sueltas; por eso el motor de arranque solo gira mientras sostienes la llave.', '{"tool":"Multímetro (V DC)","steps":["Con la llave en ON, mide la salida ON (N-IGN1): debe haber voltaje.","Al girar y sostener en START, mide la salida START (N-IGN2): solo debe tener voltaje mientras la sostienes.","Si sueltas y el voltaje de START no desaparece, o si ON se cae solo, los contactos internos están desgastados."],"normal_values":"Voltaje presente en la salida correspondiente a cada posición"}'::jsonb, '{"symptoms":["No pasa a START (el motor no cranquea).","Pierde la posición ON de forma intermitente."],"common_causes":["Contactos internos desgastados."]}'::jsonb, 'ignition-switch', 6 on conflict (id) do update set system_id = excluded.system_id, name = excluded.name, short_role = excluded.short_role, full_description = excluded.full_description, how_to_test = excluded.how_to_test, failure_signs = excluded.failure_signs, scene_key = excluded.scene_key, order_index = excluded.order_index;
insert into components (id, system_id, name, short_role, full_description, how_to_test, failure_signs, scene_key, order_index) values ('starter-relay', 'arranque-carga', 'Relé de arranque', 'Un interruptor que se acciona solo con un electroimán, para mandar mucha corriente con una orden pequeña.', 'Es un interruptor que se acciona solo. Al girar la llave a START le llega una corriente pequeña que magnetiza su bobina; esa bobina, ya convertida en imán, jala y cierra un contacto interno que deja pasar la corriente grande hacia el solenoide. Sirve para que un cable delgado (la llave) mande una corriente enorme sin quemarse.', '{"tool":"Multímetro (Ω y V DC)","steps":["Con el circuito apagado, mide la resistencia entre los dos terminales de la bobina: debe dar entre 70 y 90Ω.","Si marca 0Ω hay un corto; si marca OL, la bobina está cortada.","Aplica 12V a la bobina: debe sonar un ''clic'' y el contacto de potencia debe cerrarse (continuidad ~0Ω)."],"normal_values":"Bobina: 70–90Ω"}'::jsonb, '{"symptoms":["Silencio total al girar la llave (bobina abierta).","Clic sin paso de corriente (contactos quemados)."],"common_causes":["Bobina abierta.","Contactos quemados por uso."]}'::jsonb, 'starter-relay', 7 on conflict (id) do update set system_id = excluded.system_id, name = excluded.name, short_role = excluded.short_role, full_description = excluded.full_description, how_to_test = excluded.how_to_test, failure_signs = excluded.failure_signs, scene_key = excluded.scene_key, order_index = excluded.order_index;
insert into components (id, system_id, name, short_role, full_description, how_to_test, failure_signs, scene_key, order_index) values ('solenoid', 'arranque-carga', 'Solenoide', 'Empuja el piñón contra el volante y suelta la corriente máxima al motor de arranque.', 'Hace dos trabajos en el mismo instante cuando recibe la señal del relé: primero empuja hacia afuera el piñón del motor de arranque para que engrane con el volante del motor; y al terminar ese empujón, cierra un contacto grueso que suelta toda la corriente de la batería hacia el motor de arranque. Es el último interruptor de la cadena: sin él, el arranque ni engrana ni recibe corriente.', '{"tool":"Multímetro (V DC) + inspección auditiva","steps":["Al dar START, mide su terminal de señal: debe llegar voltaje (viene del relé).","Escucha el ''clic'' fuerte al energizarse: es el piñón saliendo y el contacto cerrando.","Clic pero sin que el motor gire = los contactos internos de potencia están gastados."],"normal_values":"Voltaje presente en terminal de señal al dar START"}'::jsonb, '{"symptoms":["Clic repetido sin que el motor gire (contactos internos gastados)."],"common_causes":["Contactos internos desgastados por el uso."]}'::jsonb, 'solenoid', 8 on conflict (id) do update set system_id = excluded.system_id, name = excluded.name, short_role = excluded.short_role, full_description = excluded.full_description, how_to_test = excluded.how_to_test, failure_signs = excluded.failure_signs, scene_key = excluded.scene_key, order_index = excluded.order_index;
insert into components (id, system_id, name, short_role, full_description, how_to_test, failure_signs, scene_key, order_index) values ('starter-motor', 'arranque-carga', 'Motor de arranque', 'Hace girar el motor de combustión para arrancarlo.', 'Motor eléctrico de alta potencia que hace girar el motor de combustión para iniciarlo. Solo trabaja segundos, pero consume muchísima corriente (80–200A). Su piñón engrana con el volante del motor a través del solenoide.', '{"tool":"Multímetro (V DC) — prueba de caída de voltaje","steps":["Durante el arranque, la batería no debe caer de 9.6V.","El terminal principal del arranque debe recibir casi el mismo voltaje que la batería.","Caída máxima aceptable en el cable: 0.5V."],"normal_values":"Caída de voltaje en el cable ≤0.5V durante el arranque"}'::jsonb, '{"symptoms":["Clic sin giro (solenoide actúa pero el motor no).","Giro lento con batería buena.","Chirrido metálico (piñón no engrana bien).","Silencio total (circuito de mando abierto)."],"common_causes":["Escobillas o casquillos gastados.","Consumo excesivo por desgaste interno.","Circuito de mando abierto."]}'::jsonb, 'starter-motor', 9 on conflict (id) do update set system_id = excluded.system_id, name = excluded.name, short_role = excluded.short_role, full_description = excluded.full_description, how_to_test = excluded.how_to_test, failure_signs = excluded.failure_signs, scene_key = excluded.scene_key, order_index = excluded.order_index;
insert into components (id, system_id, name, short_role, full_description, how_to_test, failure_signs, scene_key, order_index) values ('belt', 'arranque-carga', 'Correa de accesorios', 'Lleva el giro del motor hasta el alternador; es la única pieza mecánica del sistema de carga.', 'Es la banda de hule que une la polea del motor con la del alternador. Cuando el motor gira, arrastra la correa y la correa hace girar el alternador, y así el alternador puede generar electricidad. Es la única pieza mecánica (no eléctrica) del sistema de carga: si la correa está floja, chillando o rota, el alternador deja de cargar aunque esté en perfecto estado.', '{"tool":"Inspección visual y táctil","steps":["Revisa la tensión: debe flexionar aproximadamente 1cm al presionar.","Busca grietas en la superficie.","Observa el brillo (patina) que indica deslizamiento."],"normal_values":"Flexión ~1cm, sin grietas, sin brillo excesivo"}'::jsonb, '{"symptoms":["Chillido al acelerar.","Lámpara de carga encendida.","Sobrecalentamiento si también mueve la bomba de agua."],"common_causes":["Correa floja.","Correa agrietada o rota."]}'::jsonb, 'belt', 10 on conflict (id) do update set system_id = excluded.system_id, name = excluded.name, short_role = excluded.short_role, full_description = excluded.full_description, how_to_test = excluded.how_to_test, failure_signs = excluded.failure_signs, scene_key = excluded.scene_key, order_index = excluded.order_index;
insert into components (id, system_id, name, short_role, full_description, how_to_test, failure_signs, scene_key, order_index) values ('alternator', 'arranque-carga', 'Alternador', 'Genera electricidad para recargar la batería con el motor en marcha.', 'El generador del vehículo. Movido por la correa, transforma giro en electricidad: recarga la batería y alimenta todo el sistema con el motor en marcha. Su regulador mantiene el voltaje entre 13.8 y 14.4V.', '{"tool":"Multímetro (V DC)","steps":["Con el motor encendido, mide en la batería.","13.8–14.4V = carga bien.","Menos de 13.2V = no está cargando (revisar correa, conexiones, alternador).","Más de 14.8V = regulador dañado (peligro para batería y electrónica)."],"normal_values":"13.8–14.4V con motor encendido"}'::jsonb, '{"symptoms":["Lámpara de batería encendida en el tablero.","Batería que se descarga manejando.","Luces que oscilan.","Ruido de rodamiento o correa chillona."],"common_causes":["Correa floja o rota.","Diodos dañados.","Regulador defectuoso."]}'::jsonb, 'alternator', 11 on conflict (id) do update set system_id = excluded.system_id, name = excluded.name, short_role = excluded.short_role, full_description = excluded.full_description, how_to_test = excluded.how_to_test, failure_signs = excluded.failure_signs, scene_key = excluded.scene_key, order_index = excluded.order_index;
insert into components (id, system_id, name, short_role, full_description, how_to_test, failure_signs, scene_key, order_index) values ('charge-lamp', 'arranque-carga', 'Lámpara de carga', 'El testigo del tablero (forma de batería) que avisa si el sistema de carga trabaja.', 'El testigo del tablero con forma de batería. Funciona como un chismoso del sistema de carga: con la llave en ON y el motor apagado se enciende, y así compruebas que el bombillo sirve. Apenas arrancas y el alternador empieza a generar, debe apagarse sola. Si se queda encendida con el motor andando, te está avisando que el alternador NO está cargando la batería.', '{"tool":"Inspección visual","steps":["Con la llave en ON y el motor apagado, debe encender (prueba de bombillo).","Al arrancar el motor, debe apagarse si el alternador carga correctamente."],"normal_values":"Encendida en ON, apagada con motor en marcha"}'::jsonb, '{"symptoms":["Encendida con el motor en marcha = no hay carga.","Nunca enciende = bombillo fundido o circuito abierto."],"common_causes":["Bombillo fundido.","Circuito de la lámpara abierto.","Alternador sin carga."]}'::jsonb, 'charge-lamp', 12 on conflict (id) do update set system_id = excluded.system_id, name = excluded.name, short_role = excluded.short_role, full_description = excluded.full_description, how_to_test = excluded.how_to_test, failure_signs = excluded.failure_signs, scene_key = excluded.scene_key, order_index = excluded.order_index;
insert into lessons (id, system_id, component_id, title, estimated_minutes, steps, badge_key, order_index, prerequisite_lesson_id) values ('lec-tour', 'arranque-carga', null, 'Bienvenido al taller', 3, '[{"type":"intro","text":"Bienvenido a tu taller virtual. Aquí vas a conocer cada pieza del sistema de arranque y carga, tocarlas, medirlas y entender cómo trabajan juntas. Empecemos con un recorrido rápido."},{"type":"focus","target":"battery","text":"Esta es la batería: el punto de partida de todo el sistema eléctrico. Tócala."},{"type":"focus","target":"ignition-switch","text":"Esta es la llave de encendido: decide a dónde va la corriente. Tócala."},{"type":"focus","target":"starter-motor","text":"Este es el motor de arranque: hace girar el motor para encenderlo. Tócalo."},{"type":"focus","target":"alternator","text":"Este es el alternador: recarga la batería cuando el motor está en marcha. Tócalo."},{"type":"summary","text":"Ya conoces 4 piezas clave del sistema. En las próximas lecciones aprenderás a medirlas como un técnico real.","badge":"primera-visita"}]'::jsonb, 'primera-visita', 1, null on conflict (id) do update set system_id = excluded.system_id, component_id = excluded.component_id, title = excluded.title, estimated_minutes = excluded.estimated_minutes, steps = excluded.steps, badge_key = excluded.badge_key, order_index = excluded.order_index, prerequisite_lesson_id = excluded.prerequisite_lesson_id;
insert into lessons (id, system_id, component_id, title, estimated_minutes, steps, badge_key, order_index, prerequisite_lesson_id) values ('lec-battery', 'arranque-carga', 'battery', 'La batería: el corazón eléctrico', 4, '[{"type":"intro","text":"Todo diagnóstico eléctrico empieza aquí: la batería. Antes de culpar a cualquier otra pieza, un buen técnico verifica que la fuente de energía esté sana."},{"type":"focus","target":"battery","text":"Esta es la batería. Acércate con doble clic."},{"type":"quiz","question":"Antes de medir, ¿qué revisas a simple vista?","options":["Bornes limpios y apretados","El color de la carcasa","La marca de la batería"],"answer":0,"explanation":"Un borne sulfatado o flojo causa los mismos síntomas que una batería mala. Inspección visual SIEMPRE primero."},{"type":"measure","tool":"multimeter","mode":"V","probeA":"N-BAT+","probeB":"N-BAT-","expect":{"min":12.4,"max":12.7},"instruction":"Multímetro en V DC. Sonda roja al borne (+), negra al (−). ¿Cuánto marca?","hint":"El borne positivo es el más grueso y tiene la marca +.","wrongFeedback":{"reversed":"¿Lectura negativa? Invertiste las sondas. No daña este multímetro, pero acostúmbrate: rojo al +."}},{"type":"quiz","question":"Marcó 12.6V en reposo. ¿Qué significa?","options":["Carga completa","Batería a media carga","Sobrecarga peligrosa"],"answer":0,"explanation":"12.4–12.7V = cargada. 12.0–12.3V = media. Menos de 12.0V = descargada."},{"type":"summary","text":"Ya sabes verificar la fuente de energía del vehículo: inspección visual + medición en reposo. Próximo paso: ver qué pasa con este voltaje durante el arranque.","badge":"battery-master"}]'::jsonb, 'battery-master', 2, 'lec-tour' on conflict (id) do update set system_id = excluded.system_id, component_id = excluded.component_id, title = excluded.title, estimated_minutes = excluded.estimated_minutes, steps = excluded.steps, badge_key = excluded.badge_key, order_index = excluded.order_index, prerequisite_lesson_id = excluded.prerequisite_lesson_id;
insert into lessons (id, system_id, component_id, title, estimated_minutes, steps, badge_key, order_index, prerequisite_lesson_id) values ('lec-terminals', 'arranque-carga', 'terminal-pos', 'Bornes y conexiones', 4, '[{"type":"intro","text":"Un borne sulfatado o flojo puede causar los mismos síntomas que una batería mala. Por eso siempre se revisan antes de sospechar de la batería."},{"type":"focus","target":"terminal-pos","text":"Este es el borne positivo. Acércate y obsérvalo."},{"type":"quiz","question":"¿Qué buscas primero en una inspección visual del borne?","options":["Sulfatación (polvo blanco/verde) o borne flojo","El color del cable","La marca del fabricante"],"answer":0,"explanation":"La sulfatación y los bornes flojos son la causa más común de fallos de contacto."},{"type":"measure","tool":"multimeter","mode":"V","probeA":"N-BAT+","probeB":"N-MAIN","expect":{"min":0,"max":0.1},"instruction":"Con el motor cranqueando, mide la caída de voltaje entre el borne positivo y el cable. ¿Cuánto marca?","hint":"Una caída sana es menor a 0.1V.","wrongFeedback":{"reversed":"Lectura negativa: invertiste las sondas."}},{"type":"summary","text":"Aprendiste a revisar el borne positivo antes de culpar a la batería. El borne negativo se revisa exactamente igual.","badge":"buen-contacto"}]'::jsonb, 'buen-contacto', 3, 'lec-battery' on conflict (id) do update set system_id = excluded.system_id, component_id = excluded.component_id, title = excluded.title, estimated_minutes = excluded.estimated_minutes, steps = excluded.steps, badge_key = excluded.badge_key, order_index = excluded.order_index, prerequisite_lesson_id = excluded.prerequisite_lesson_id;
insert into lessons (id, system_id, component_id, title, estimated_minutes, steps, badge_key, order_index, prerequisite_lesson_id) values ('lec-ground', 'arranque-carga', 'ground-strap', 'La masa: el circuito de retorno', 4, '[{"type":"intro","text":"El circuito necesita un camino de regreso a la batería. Ese camino es la masa: la trenza que conecta el negativo al chasis o al bloque del motor."},{"type":"focus","target":"ground-strap","text":"Esta es la trenza de masa. Sin ella, el circuito no cierra."},{"type":"measure","tool":"multimeter","mode":"Ω","probeA":"N-BAT-","probeB":"N-GND","expect":{"min":0,"max":0.5},"instruction":"Circuito desenergizado: mide la resistencia de la trenza de masa. ¿Cuánto marca?","hint":"Una trenza sana marca aproximadamente 0Ω.","wrongFeedback":{"open":"OL significa que no hay continuidad: la trenza está rota o muy corroída."}},{"type":"quiz","question":"Una trenza de masa corroída puede causar...","options":["Luces raras y arranque débil sin causa aparente","Que el claxon suene solo","Que se caliente el radiador"],"answer":0,"explanation":"La corrosión en la masa produce fallas \"fantasma\": el circuito nunca cierra del todo."},{"type":"summary","text":"La masa es tan importante como el positivo. Un técnico siempre la revisa cuando algo eléctrico falla sin explicación.","badge":"tierra-firme"}]'::jsonb, 'tierra-firme', 4, 'lec-terminals' on conflict (id) do update set system_id = excluded.system_id, component_id = excluded.component_id, title = excluded.title, estimated_minutes = excluded.estimated_minutes, steps = excluded.steps, badge_key = excluded.badge_key, order_index = excluded.order_index, prerequisite_lesson_id = excluded.prerequisite_lesson_id;
insert into lessons (id, system_id, component_id, title, estimated_minutes, steps, badge_key, order_index, prerequisite_lesson_id) values ('lec-fuse', 'arranque-carga', 'main-fuse', 'Fusibles: los guardianes', 4, '[{"type":"intro","text":"Antes de que la corriente llegue a cualquier parte del sistema, pasa por el fusible principal: el guardián que se sacrifica para proteger el resto del cableado."},{"type":"focus","target":"main-fuse","text":"Este es el fusible principal de 80A."},{"type":"measure","tool":"multimeter","mode":"Ω","probeA":"N-BAT+","probeB":"N-MAIN","expect":{"min":0,"max":0.5},"instruction":"Circuito desenergizado: mide la continuidad del fusible sano. ¿Cuánto marca?","hint":"Un fusible sano marca aproximadamente 0Ω.","wrongFeedback":{"open":"OL significa que el fusible está quemado: no hay continuidad."}},{"type":"quiz","question":"Si el multímetro marca OL al medir el fusible, ¿qué significa?","options":["Está quemado: no hay continuidad","Está perfecto","Falta apretar los bornes"],"answer":0,"explanation":"OL = circuito abierto. Un fusible quemado se comporta exactamente así."},{"type":"summary","text":"Un sistema muerto de repente, sin luces ni nada, casi siempre empieza por revisar el fusible principal.","badge":"guardian"}]'::jsonb, 'guardian', 5, 'lec-ground' on conflict (id) do update set system_id = excluded.system_id, component_id = excluded.component_id, title = excluded.title, estimated_minutes = excluded.estimated_minutes, steps = excluded.steps, badge_key = excluded.badge_key, order_index = excluded.order_index, prerequisite_lesson_id = excluded.prerequisite_lesson_id;
insert into lessons (id, system_id, component_id, title, estimated_minutes, steps, badge_key, order_index, prerequisite_lesson_id) values ('lec-switch', 'arranque-carga', 'ignition-switch', 'La llave de encendido', 5, '[{"type":"intro","text":"La llave de encendido dirige la corriente según su posición: apagado, contacto (ON) o arranque (START)."},{"type":"focus","target":"ignition-switch","text":"Esta es la llave. Recorre mentalmente sus 3 posiciones: OFF → ON → START."},{"type":"toggle","target":"ignition-switch","instruction":"Gira la llave a la posición ON.","expect":{"ignition":"on"}},{"type":"measure","tool":"multimeter","mode":"V","probeA":"N-IGN1","probeB":"N-GND","expect":{"min":12.2,"max":12.4},"instruction":"Con la llave en ON, mide la salida N-IGN1. ¿Cuánto marca?","hint":"En ON debe haber corriente en esta salida."},{"type":"toggle","target":"ignition-switch","instruction":"Ahora gira la llave a START.","expect":{"ignition":"crank"}},{"type":"measure","tool":"multimeter","mode":"V","probeA":"N-IGN2","probeB":"N-GND","expect":{"min":10.2,"max":10.4},"instruction":"Con la llave en START, mide la salida N-IGN2. ¿Cuánto marca?","hint":"Esta salida solo tiene corriente mientras se sostiene en START."},{"type":"summary","text":"Ya sabes qué hace la llave en cada posición y cómo verificarlo con el multímetro.","badge":"llavero"}]'::jsonb, 'llavero', 6, 'lec-fuse' on conflict (id) do update set system_id = excluded.system_id, component_id = excluded.component_id, title = excluded.title, estimated_minutes = excluded.estimated_minutes, steps = excluded.steps, badge_key = excluded.badge_key, order_index = excluded.order_index, prerequisite_lesson_id = excluded.prerequisite_lesson_id;
insert into lessons (id, system_id, component_id, title, estimated_minutes, steps, badge_key, order_index, prerequisite_lesson_id) values ('lec-relay', 'arranque-carga', 'starter-relay', 'El relé: pequeño interruptor gigante', 4, '[{"type":"intro","text":"El relé de arranque es un interruptor electromagnético: la llave energiza su bobina y el contacto manda la corriente grande hacia el solenoide."},{"type":"focus","target":"starter-relay","text":"Este es el relé de arranque."},{"type":"measure","tool":"multimeter","mode":"Ω","probeA":"N-IGN2","probeB":"N-GND","expect":{"min":70,"max":90},"instruction":"Circuito desenergizado: mide la resistencia de la bobina del relé. ¿Cuánto marca?","hint":"Un relé sano marca entre 70 y 90Ω.","wrongFeedback":{"open":"OL significa que la bobina está abierta: el relé no va a energizarse nunca."}},{"type":"quiz","question":"Si la bobina del relé marca OL, ¿qué esperas al girar la llave a START?","options":["Silencio total: ni siquiera un clic","Un clic fuerte y arranque normal","Las luces del tablero parpadean"],"answer":0,"explanation":"Bobina abierta = no hay forma de energizar el relé. No hay clic ni arranque."},{"type":"summary","text":"El relé es pequeño pero decide si toda la corriente de arranque llega al solenoide.","badge":"clic-perfecto"}]'::jsonb, 'clic-perfecto', 7, 'lec-switch' on conflict (id) do update set system_id = excluded.system_id, component_id = excluded.component_id, title = excluded.title, estimated_minutes = excluded.estimated_minutes, steps = excluded.steps, badge_key = excluded.badge_key, order_index = excluded.order_index, prerequisite_lesson_id = excluded.prerequisite_lesson_id;
insert into lessons (id, system_id, component_id, title, estimated_minutes, steps, badge_key, order_index, prerequisite_lesson_id) values ('lec-solenoid', 'arranque-carga', 'solenoid', 'El solenoide', 4, '[{"type":"intro","text":"El solenoide hace dos cosas a la vez: empuja el piñón del arranque para que engrane, y conecta la corriente máxima hacia el motor de arranque."},{"type":"focus","target":"solenoid","text":"Este es el solenoide, montado sobre el motor de arranque."},{"type":"toggle","target":"ignition-switch","instruction":"Da START para energizar el solenoide.","expect":{"ignition":"crank"}},{"type":"measure","tool":"multimeter","mode":"V","probeA":"N-SOL","probeB":"N-GND","expect":{"min":10.1,"max":10.3},"instruction":"Con la llave en START, mide la señal del solenoide (N-SOL). ¿Cuánto marca?","hint":"Debe verse un voltaje similar al de la batería en crank."},{"type":"quiz","question":"Escuchas \"clic, clic, clic\" pero el motor no gira. ¿Qué sugiere?","options":["Contactos internos del solenoide gastados","La batería está perfecta","El fusible está quemado"],"answer":0,"explanation":"El clic confirma que el solenoide se energiza, pero si no pasa corriente suficiente, sus contactos internos están gastados."},{"type":"summary","text":"El solenoide es el puente entre \"decidir arrancar\" y \"tener la fuerza para hacerlo\".","badge":"empuje-justo"}]'::jsonb, 'empuje-justo', 8, 'lec-relay' on conflict (id) do update set system_id = excluded.system_id, component_id = excluded.component_id, title = excluded.title, estimated_minutes = excluded.estimated_minutes, steps = excluded.steps, badge_key = excluded.badge_key, order_index = excluded.order_index, prerequisite_lesson_id = excluded.prerequisite_lesson_id;
insert into lessons (id, system_id, component_id, title, estimated_minutes, steps, badge_key, order_index, prerequisite_lesson_id) values ('lec-starter', 'arranque-carga', 'starter-motor', 'El motor de arranque', 5, '[{"type":"intro","text":"Es momento del arranque completo: la pieza que hace girar el motor para que encienda."},{"type":"focus","target":"starter-motor","text":"Este es el motor de arranque."},{"type":"toggle","target":"ignition-switch","instruction":"Da START y sostenlo.","expect":{"ignition":"crank"}},{"type":"measure","tool":"multimeter","mode":"V","probeA":"N-BAT+","probeB":"N-BAT-","expect":{"min":9.6,"max":10.8},"instruction":"Durante el crank, mide la batería. ¿Cuánto marca?","hint":"Una caída sana durante el arranque va de 9.6V a 10.8V."},{"type":"measure","tool":"multimeter","mode":"V","probeA":"N-STARTER","probeB":"N-GND","expect":{"min":9.6,"max":10.2},"instruction":"Ahora mide directamente el terminal del motor de arranque. ¿Cuánto marca?","hint":"Debe ser casi igual al voltaje de la batería: la caída máxima aceptable en el cable es 0.5V."},{"type":"quiz","question":"¿Cuál es la caída de voltaje máxima aceptable entre la batería y el terminal del arranque durante el crank?","options":["0.5V","3V","No debe haber ninguna diferencia"],"answer":0,"explanation":"Más de 0.5V de diferencia indica un cable o conexión con problemas."},{"type":"summary","text":"Sentiste la \"primera chispa\": el corazón del sistema de arranque funcionando de punta a punta.","badge":"primera-chispa"}]'::jsonb, 'primera-chispa', 9, 'lec-solenoid' on conflict (id) do update set system_id = excluded.system_id, component_id = excluded.component_id, title = excluded.title, estimated_minutes = excluded.estimated_minutes, steps = excluded.steps, badge_key = excluded.badge_key, order_index = excluded.order_index, prerequisite_lesson_id = excluded.prerequisite_lesson_id;
insert into lessons (id, system_id, component_id, title, estimated_minutes, steps, badge_key, order_index, prerequisite_lesson_id) values ('lec-belt', 'arranque-carga', 'belt', 'La correa de accesorios', 3, '[{"type":"intro","text":"Ahora pasamos al circuito de carga. Todo empieza con la correa: sin giro, no hay generación de electricidad."},{"type":"focus","target":"belt","text":"Esta es la correa de accesorios."},{"type":"quiz","question":"¿Cómo se revisa una correa sana?","options":["Tensión de ~1cm de flexión, sin grietas ni brillo excesivo","Solo por el color","Escuchando el motor apagado"],"answer":0,"explanation":"La inspección visual y táctil es la prueba principal de la correa."},{"type":"order","instruction":"Ordena los pasos de la inspección de la correa:","items":["Presionar y medir la flexión (~1cm)","Buscar grietas en la superficie","Observar el brillo (pátina) que indica deslizamiento"],"answer":[0,1,2]},{"type":"summary","text":"Una correa floja o agrietada es una de las causas más comunes de fallas del sistema de carga.","badge":"tension-justa"}]'::jsonb, 'tension-justa', 10, 'lec-starter' on conflict (id) do update set system_id = excluded.system_id, component_id = excluded.component_id, title = excluded.title, estimated_minutes = excluded.estimated_minutes, steps = excluded.steps, badge_key = excluded.badge_key, order_index = excluded.order_index, prerequisite_lesson_id = excluded.prerequisite_lesson_id;
insert into lessons (id, system_id, component_id, title, estimated_minutes, steps, badge_key, order_index, prerequisite_lesson_id) values ('lec-alternator', 'arranque-carga', 'alternator', 'El alternador: la planta generadora', 4, '[{"type":"intro","text":"El alternador es la planta generadora del vehículo: convierte el giro de la correa en la electricidad que recarga la batería."},{"type":"focus","target":"alternator","text":"Este es el alternador."},{"type":"toggle","target":"ignition-switch","instruction":"Enciende el motor.","expect":{"engineRunning":true}},{"type":"measure","tool":"multimeter","mode":"V","probeA":"N-ALT-B+","probeB":"N-GND","expect":{"min":13.8,"max":14.4},"instruction":"Con el motor encendido, mide en el terminal B+ del alternador. ¿Cuánto marca?","hint":"Un alternador sano regula entre 13.8 y 14.4V."},{"type":"quiz","question":"El alternador marca 12.3V con el motor encendido. ¿Qué significa?","options":["No está cargando: revisar correa, conexiones o el alternador","Está perfecto","Está sobrecargando la batería"],"answer":0,"explanation":"Menos de 13.2V con el motor en marcha indica que el sistema no está cargando."},{"type":"summary","text":"Ya sabes confirmar si el sistema de carga está funcionando con una sola medición.","badge":"generador"}]'::jsonb, 'generador', 11, 'lec-belt' on conflict (id) do update set system_id = excluded.system_id, component_id = excluded.component_id, title = excluded.title, estimated_minutes = excluded.estimated_minutes, steps = excluded.steps, badge_key = excluded.badge_key, order_index = excluded.order_index, prerequisite_lesson_id = excluded.prerequisite_lesson_id;
insert into lessons (id, system_id, component_id, title, estimated_minutes, steps, badge_key, order_index, prerequisite_lesson_id) values ('lec-lamp', 'arranque-carga', 'charge-lamp', 'La lámpara de carga', 4, '[{"type":"intro","text":"El tablero tiene un testigo silencioso del sistema de carga: la lámpara de batería."},{"type":"focus","target":"charge-lamp","text":"Esta es la lámpara de carga del tablero."},{"type":"toggle","target":"ignition-switch","instruction":"Pon la llave en ON (motor apagado).","expect":{"ignition":"on"}},{"type":"quiz","question":"¿Cómo debe verse la lámpara de carga con la llave en ON y el motor apagado?","options":["Encendida (prueba de bombillo)","Apagada","Parpadeando"],"answer":0,"explanation":"Encendida en ON confirma que el bombillo y el circuito de la lámpara funcionan."},{"type":"toggle","target":"ignition-switch","instruction":"Ahora enciende el motor.","expect":{"engineRunning":true}},{"type":"quiz","question":"Con el motor encendido, la lámpara sigue encendida. ¿Qué indica?","options":["No hay carga: revisar el sistema de carga","Todo está perfecto","Falta gasolina"],"answer":0,"explanation":"Si la lámpara no se apaga al arrancar, el alternador no está cargando correctamente."},{"type":"summary","text":"Aprendiste a leer un testigo del tablero como una fuente real de diagnóstico.","badge":"ojo-de-aguila"}]'::jsonb, 'ojo-de-aguila', 12, 'lec-alternator' on conflict (id) do update set system_id = excluded.system_id, component_id = excluded.component_id, title = excluded.title, estimated_minutes = excluded.estimated_minutes, steps = excluded.steps, badge_key = excluded.badge_key, order_index = excluded.order_index, prerequisite_lesson_id = excluded.prerequisite_lesson_id;
insert into lessons (id, system_id, component_id, title, estimated_minutes, steps, badge_key, order_index, prerequisite_lesson_id) values ('lec-charge-circuit', 'arranque-carga', null, '🔗 Integradora: el ciclo de carga', 5, '[{"type":"intro","text":"🔗 Lección integradora: vas a recorrer el circuito de carga completo, de reposo a motor encendido, en una sola secuencia."},{"type":"measure","tool":"multimeter","mode":"V","probeA":"N-BAT+","probeB":"N-BAT-","expect":{"min":12.4,"max":12.7},"instruction":"Con el motor apagado, mide la batería en reposo.","hint":"Cargada: 12.4–12.7V."},{"type":"toggle","target":"ignition-switch","instruction":"Enciende el motor.","expect":{"engineRunning":true}},{"type":"measure","tool":"multimeter","mode":"V","probeA":"N-BAT+","probeB":"N-BAT-","expect":{"min":13.8,"max":14.4},"instruction":"Ahora, con el motor encendido, vuelve a medir la batería.","hint":"Debe subir a 13.8–14.4V: el alternador está cargando."},{"type":"measure","tool":"multimeter","mode":"V","probeA":"N-ALT-B+","probeB":"N-GND","expect":{"min":13.8,"max":14.4},"instruction":"Confirma midiendo directamente en el alternador (B+).","hint":"Debe coincidir con la lectura de la batería."},{"type":"quiz","question":"¿Qué demuestra que el voltaje suba de 12.6V a 14.1V al encender el motor?","options":["Que el alternador está generando y cargando la batería","Que la batería está fallando","Que hay un cortocircuito"],"answer":0,"explanation":"Ese salto de voltaje es la firma de un sistema de carga sano."},{"type":"summary","text":"Completaste el ciclo completo de carga: de reposo a generación activa, con evidencia en cada paso.","badge":"circuito-completo"}]'::jsonb, 'circuito-completo', 13, 'lec-lamp' on conflict (id) do update set system_id = excluded.system_id, component_id = excluded.component_id, title = excluded.title, estimated_minutes = excluded.estimated_minutes, steps = excluded.steps, badge_key = excluded.badge_key, order_index = excluded.order_index, prerequisite_lesson_id = excluded.prerequisite_lesson_id;
insert into lessons (id, system_id, component_id, title, estimated_minutes, steps, badge_key, order_index, prerequisite_lesson_id) values ('lec-start-circuit', 'arranque-carga', null, '🔗 Integradora: anatomía de un arranque', 5, '[{"type":"intro","text":"🔗 Lección integradora: vas a reconstruir la cadena completa de arranque, de la llave al volante del motor."},{"type":"order","instruction":"Ordena la cadena del sistema de arranque, de principio a fin:","items":["Llave en START","Relé de arranque","Solenoide","Motor de arranque","Volante del motor"],"answer":[0,1,2,3,4]},{"type":"toggle","target":"ignition-switch","instruction":"Da START y sostenlo.","expect":{"ignition":"crank"}},{"type":"measure","tool":"multimeter","mode":"V","probeA":"N-IGN2","probeB":"N-GND","expect":{"min":10.2,"max":10.4},"instruction":"Mide la salida START de la llave (N-IGN2).","hint":"Debe tener voltaje solo mientras sostienes START."},{"type":"measure","tool":"multimeter","mode":"V","probeA":"N-SOL","probeB":"N-GND","expect":{"min":10.1,"max":10.3},"instruction":"Mide la señal del solenoide (N-SOL).","hint":"Confirma que la señal llegó desde el relé."},{"type":"measure","tool":"multimeter","mode":"V","probeA":"N-STARTER","probeB":"N-GND","expect":{"min":9.6,"max":10.2},"instruction":"Finalmente, mide el terminal del motor de arranque.","hint":"Debe ser casi igual al voltaje de la batería en crank."},{"type":"summary","text":"Reconstruiste toda la cadena de arranque, midiendo la evidencia eléctrica en cada eslabón.","badge":"anatomia-del-arranque"}]'::jsonb, 'anatomia-del-arranque', 14, 'lec-charge-circuit' on conflict (id) do update set system_id = excluded.system_id, component_id = excluded.component_id, title = excluded.title, estimated_minutes = excluded.estimated_minutes, steps = excluded.steps, badge_key = excluded.badge_key, order_index = excluded.order_index, prerequisite_lesson_id = excluded.prerequisite_lesson_id;
insert into lessons (id, system_id, component_id, title, estimated_minutes, steps, badge_key, order_index, prerequisite_lesson_id) values ('lec-workshop-pro', 'arranque-carga', null, '🔗 Procedimiento profesional de taller', 5, '[{"type":"intro","text":"🔗 Última lección: el procedimiento profesional de taller. No se trata solo de saber medir, sino de hacerlo en el orden correcto y seguro."},{"type":"quiz","question":"Antes de cualquier medición eléctrica, ¿qué debes quitarte de manos y muñecas?","options":["Objetos metálicos (anillos, relojes, pulseras)","Los guantes","Nada, no es necesario"],"answer":0,"explanation":"Los objetos metálicos pueden causar cortocircuitos peligrosos cerca de la batería."},{"type":"order","instruction":"Ordena el protocolo profesional de diagnóstico:","items":["Seguridad: quitar objetos metálicos","Inspección visual general","Verificar la batería primero","Realizar las pruebas específicas","Registrar los resultados"],"answer":[0,1,2,3,4]},{"type":"quiz","question":"¿Por qué la batería se revisa primero, antes que cualquier otra pieza?","options":["Porque una batería débil puede simular fallas en todo el sistema","Porque es la pieza más cara","Porque así lo dice la ley"],"answer":0,"explanation":"Sin descartar la batería primero, puedes perseguir síntomas que en realidad vienen de ahí."},{"type":"summary","text":"Ya conoces el sistema de arranque y carga completo, y el protocolo con el que un técnico profesional trabaja. Bienvenido a ZR Mecademy.","badge":"tecnico-en-formacion"}]'::jsonb, 'tecnico-en-formacion', 15, 'lec-start-circuit' on conflict (id) do update set system_id = excluded.system_id, component_id = excluded.component_id, title = excluded.title, estimated_minutes = excluded.estimated_minutes, steps = excluded.steps, badge_key = excluded.badge_key, order_index = excluded.order_index, prerequisite_lesson_id = excluded.prerequisite_lesson_id;
